code.C:
#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        scanf("%d", &N);
        int x = 1;
        int y = 1;
        for (int j = 0; j < N; j++) {
            y *= 2;
        }
        printf("%d %d ", x, y);
    }
    return 0;
}

